44			generic (
45				N			: positive																			-- Length of Token Chain
46			);
47			port (
48				tin		: in	std_logic		:= '1';												-- Enable:		Fed Token
49				rqst	: in	std_logic_vector(N-1 downto 0);						-- Request:		Token Requests
50				grnt	: out std_logic_vector(N-1 downto 0);						-- Grant:			Token Output
51				tout	: out std_logic;											 					-- Inactive:	Unused Token
52				bin		: out std_logic_vector(log2ceil(N)-1 downto 0)	-- Binary Grant Index
53			);
54		end component;
