67			generic (
68				BITS	: positive;								-- Bit width of the counter
69				INIT	: natural					:= 0		-- Initial/reset counter value
70			);
71			port (
72				clk		: in	std_logic;
73				rst		: in	std_logic;													-- Reset to INIT value
74				inc		: in	std_logic;													-- Increment
75				dec		: in	std_logic		:= '0';									-- Decrement
76				val		: out std_logic_vector(BITS-1 downto 0);	-- Value output
77				cry		: out std_logic														-- Carry output
78			);
79		end component;
