81		-- This function computes the latency of the sequential divider, both for the
82		-- pipelined and the regular sequential implementation. The returned value
83		-- specifies the number of cycles it takes after asserting start for the
84		-- result to become ready.
85	  function arith_div_latency(a_bits, rapow : positive) return positive;
86	
87		component arith_div
88			generic (
89				A_BITS             : positive;  		    -- Dividend Width
90				D_BITS             : positive;  		    -- Divisor Width
91				RAPOW              : positive := 1;     -- Power of Compute Radix (2**RAPOW)
92				PIPELINED          : boolean  := false  -- Computation Pipeline
93			);
94			port (
95				-- Global Reset/Clock
96				clk : in std_logic;
97				rst : in std_logic;
98	
99	      -- Ready / Start
100	      start : in  std_logic;
101	      ready : out std_logic;
102	
103				-- Arguments / Result (2's complement)
104				A : in  std_logic_vector(A_BITS-1 downto 0);  -- Dividend
105				D : in  std_logic_vector(D_BITS-1 downto 0);  -- Divisor
106				Q : out std_logic_vector(A_BITS-1 downto 0);  -- Quotient
107				R : out std_logic_vector(D_BITS-1 downto 0);  -- Remainder
108				Z : out std_logic  -- Division by Zero
109			);
