149				N		: positive
150			);
151			port (
152				rst			: in	std_logic;
153				clk			: in	std_logic;
154				arg			: in	std_logic_vector(N-1 downto 0);
155				start		: in	std_logic;
156				sqrt		: out std_logic_vector((N-1)/2 downto 0);
157				rdy			: out std_logic
158			);
159		end component;
160	
161		type tArch		 is (AAM, CAI, CCA, PAI);
162		type tBlocking is (DFLT, FIX, ASC, DESC);
163		type tSkipping is (PLAIN, CCC, PPN_KS, PPN_BK);
