165		component arith_addw is
166			generic (
167				N						: positive;						-- Operand Width
168				K						: positive;						-- Block Count
169	
170				ARCH				: tArch			:= AAM;		-- Architecture
171				BLOCKING		: tBlocking	:= DFLT;	-- Blocking Scheme
172				SKIPPING		: tSkipping	:= CCC;		-- Carry Skip Scheme
