200				X		: in	std_logic_vector(BITS - 1 downto 0);
201				CIn	: in	std_logic															:= '1';
202				Y		: out	std_logic_vector(BITS - 1 downto 0)
203			);
204		end component;
205	
206		component arith_prefix_and_xilinx is
207			generic (
208				N : positive
209			);
210			port (
211				x : in	std_logic_vector(N-1 downto 0);
212				y : out std_logic_vector(N-1 downto 0)
213			);
214		end component;
215	
216		component arith_prefix_or_xilinx is
217			generic (
218				N : positive
219			);
220			port (
221				x : in	std_logic_vector(N-1 downto 0);
222				y : out std_logic_vector(N-1 downto 0)
223			);
224		end component;
