226		component arith_inc_ovcy_xilinx is
227			generic (
228				N		: positive												 		-- Bit Width
229			);
230			port (
231				p		: in	std_logic_vector(N-1 downto 0);	-- Argument
232				g		: in	std_logic;											-- Increment Guard
233				v		: out std_logic												-- Overflow Output
234			);
235		end component;
236	end package;
