41	entity arith_counter_free is
42		generic (
43			DIVIDER : positive
44		);
45		port (
46			-- Global Control
47			clk : in	std_logic;
48			rst : in	std_logic;
49	
50			inc : in  std_logic;
51	    stb : out std_logic  								-- End-of-Period Strobe
52	  );
53	end entity arith_counter_free;
54	
55	
56	library IEEE;
57	use IEEE.numeric_std.all;
58	
59	library PoC;
60	use PoC.utils.all;
61	
62	architecture rtl of arith_counter_free is
63	begin
64	
65		genNoDiv: if DIVIDER = 1 generate
66			process(clk)
67			begin
68				if rising_edge(clk) then
69					stb <= inc;
70				end if;
71			end process;
72		end generate genNoDiv;
73		genDoDiv: if DIVIDER > 1 generate
74			-- Note: For DIVIDER=2**K+1, this could be marginally reduced to log2ceil(DIVIDER-1)
75			--       if it was known that the increment input inc would never be deasserted.
76			constant N : natural := log2ceil(DIVIDER);
77			signal Cnt : unsigned(N downto 0) := (others => '0');
78	
79			signal cin : unsigned(0 downto 0);
80		begin
81			cin(0) <= not inc;
82			process(clk)
83			begin
84				if rising_edge(clk) then
85					if rst = '1' then
86						Cnt <= to_unsigned(DIVIDER-2, N+1);
87					else
88						Cnt <= Cnt + ite(Cnt(N) = '0', (Cnt'range => '1'), to_unsigned(DIVIDER-1, N+1)) + cin;
89					end if;
90				end if;
91			end process;
92			stb <= Cnt(N);
93		end generate genDoDiv;
94	
95	end rtl;
