39	-- WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
40	-- See the License for the specific language governing permissions and
41	-- limitations under the License.
42	-- =============================================================================
43	
44	library IEEE;
45	use IEEE.std_logic_1164.all;
46	
47	library PoC;
48	use PoC.utils.all;
49	
50	entity arith_firstone is
51	  generic (
52	    N : positive                                -- Length of Token Chain
53	  );
54	  port (
55	    tin  : in  std_logic := '1';                -- Enable:   Fed Token
56	    rqst : in  std_logic_vector(N-1 downto 0);  -- Request:  Token Requests
57	    grnt : out std_logic_vector(N-1 downto 0);  -- Grant:    Token Output
58	    tout : out std_logic;                       -- Inactive: Unused Token
59	    bin  : out std_logic_vector(log2ceil(N)-1 downto 0)  -- Binary Grant Index
60	  );
61	end entity arith_firstone;
62	
63	
64	library IEEE;
65	use IEEE.numeric_std.all;
66	
67	library PoC;
68	use PoC.config.all;
69	
70	architecture rtl of arith_firstone is
71	begin
72	  -- Generic Carry Chain through Addition
73	  genGeneric: if VENDOR /= VENDOR_XILINX or N < 6 generate
74	    process(rqst, tin)
75	      variable onehot : std_logic_vector(grnt'range);
76	      variable binary : unsigned(bin'range);
77				variable adder : unsigned(N downto 0);
78	    begin
79				adder  := ("0" & unsigned(not rqst)) + (1 to 1 => tin);
80	      onehot := std_logic_vector(adder(N-1 downto 0)) and rqst;
81	      binary := (others => '0');
82	      for i in onehot'range loop
83	        if onehot(i) = '1' then
84	          binary := binary or to_unsigned(i, binary'length);
85	        end if;
86	      end loop;
87				tout <= adder(N);
88	      grnt <= onehot;
89	      bin  <= std_logic_vector(binary);
90	    end process;
91	  end generate genGeneric;
92	
93	  -- Optimized Xilinx Carry Chain by MUXCY Instantiation
94	  genXilinx: if VENDOR = VENDOR_XILINX and N >= 6 generate
95	    component MUXCY
96	      port (
97	        S  : in  std_logic;
98	        DI : in  std_logic;
99	        CI : in  std_logic;
100	        O  : out std_logic
101	      );
102	    end component;
103	
104	    signal p : std_logic_vector(N-1 downto 0);  -- Propagates
105	    signal q : std_logic_vector(N   downto 0);  -- Carries = Intermediate Tokens
106	  begin
107	
108	    -- Propagate if no local Request
109	    p <= not rqst;
110	
111	    -- Token Input
112	    q(0) <= to_X01(tin);
113	
114	    -- Token Forwarding Chain
115	    genChain: for i in 0 to N-1 generate
116	      signal pp, cc : std_logic;
117	      signal qq     : std_logic_vector(1 downto 0);
118	    begin
119	
120	      -- q(i+1) <= q(i) and p(i)
121	
122	      -- First MUXCY only with switching LUT
123	      genFirst: if i = 0 generate
124	        pp <= q(0) and p(0);
125	        cc <= '1';
126	      end generate;
127	
128	      -- Others using Carry Input
129	      genChain: if i > 0 generate
130	        pp <= p(i);
131	        cc <= q(i);
132	      end generate genChain;
133	
134	      MUXCY_inst : MUXCY
135	        port map (
136	          O  => q(i+1),
137	          CI => cc,
138	          DI => '0',
139	          S  => pp
140	        );
141	
142	      -- Compute Grant
143	      qq <= q(i+1 downto i);
144	      with qq select grnt(i) <=
145	        '0' when "00" | "11",
146	        '1' when "01",
147	        'X' when others;
148	
149	    end generate;
150	
151	    -- Token Output
152	    tout <= q(N);
153	
154	    -- Recode to Binary
155	    process(q)
156	      variable b : std_logic;
157	    begin
158	      for i in 0 to log2ceil(N)-1 loop
159	        b := '0';
160	        for j in 0 to (N+(2**i)-1)/(2**(i+1))-1 loop
161	          b := b or (q((2**i) + j*(2**(i+1))) and not q(imin(N, (2**(i+1)) + j*(2**(i+1)))));
162	        end loop;
163	        bin(i) <= b;
164	      end loop;
165	    end process;
166	
167	  end generate genXilinx;
168	
169	end rtl;
